<span class="line"><span style="${s({ '--shiki-light': '#24292E', '--shiki-dark': '#E1E4E8' })}">          loaders: [</span><span style="${s({ '--shiki-light': '#032F62', '--shiki-dark': '#9ECBFF' })}">&#39;@svgr/webpack&#39;</span><span style="${s({ '--shiki-light': '#24292E', '--shiki-dark': '#E1E4E8' })}">],</span></span>
